import{_ as o,o as a,c as d,ag as i}from"./chunks/framework.BiCIjUVY.js";const u=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),l={name:"changelog.md"};function c(r,e,t,n,s,h){return a(),d("div",null,e[0]||(e[0]=[i('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><h2 id="_2026-03-20-v7-8-0-released" tabindex="-1">2026.03.20 v7.8.0 (Released) <a class="header-anchor" href="#_2026-03-20-v7-8-0-released" aria-label="Permalink to &quot;2026.03.20 v7.8.0 (Released)&quot;">​</a></h2><p><strong>v7.8.0 &quot;Foundation Solidification&quot; Release!</strong></p><p>This release focuses on quality assurance, ensuring users can confidently use the tool.</p><h3 id="core-improvements" tabindex="-1">Core Improvements <a class="header-anchor" href="#core-improvements" aria-label="Permalink to &quot;Core Improvements&quot;">​</a></h3><ol><li>Fixed build compatibility issue with <code>import ... with { type: &#39;json&#39; }</code> syntax</li><li>Migrated ESLint configuration to <code>@eslint-sets/eslint-config</code></li><li>Migrated sub-package devDependencies to use pnpm <code>catalog:</code> format for centralized version management</li><li>Added <code>catalog</code> configuration to <code>pnpm-workspace.yaml</code> for unified dependency versions</li><li>Changed publish script from <code>npm publish</code> to <code>pnpm publish</code> for automatic workspace protocol conversion</li><li>Fixed lint errors across multiple files</li><li>Extracted common <code>AnyFunction</code> type for callback function signatures</li><li>Optimized README documentation structure</li><li>Upgraded dependencies</li></ol><h3 id="test-coverage-significantly-improved" tabindex="-1">Test Coverage Significantly Improved <a class="header-anchor" href="#test-coverage-significantly-improved" aria-label="Permalink to &quot;Test Coverage Significantly Improved&quot;">​</a></h3><ul><li>Expanded test coverage for <code>@gitmars/git</code> package from 5.4% to 82.67%</li><li>Added comprehensive tests for git functions: getConfig, readPkg, searchBranches, getAheadLogs, getBehindLogs, getBranchesFromID, getGitLogs, getGitLogsByCommitIDs, checkout, fetch, prune, checkGitStatus, getStashList, getCommandMessage, getIsMergeAction, getIsMergedTargetBranch, getIsUpdatedInTime</li><li>Added <code>@gitmars/gitmars</code> core workflow test files: <ul><li><code>commands.test.ts</code> - Core command tests (start, update, combine, end)</li><li><code>workflow.test.ts</code> - Workflow tests (copy, undo, redo, save, get)</li><li><code>p0-validation.test.ts</code> - P0 priority command validation tests</li><li><code>error-handling.test.ts</code> - Error handling and boundary case tests</li></ul></li><li>Total test cases reached <strong>422+</strong>, with <strong>10</strong> test files and over <strong>4355</strong> lines of test code</li></ul><h3 id="v7-8-0-acceptance-criteria-achieved" tabindex="-1">v7.8.0 Acceptance Criteria Achieved <a class="header-anchor" href="#v7-8-0-acceptance-criteria-achieved" aria-label="Permalink to &quot;v7.8.0 Acceptance Criteria Achieved&quot;">​</a></h3><ul><li>[x] Core workflow test coverage ≥70%</li><li>[x] All P0 command functionality verified</li><li>[x] Quick start documentation complete</li><li>[x] Zero P1 level bugs</li></ul><h2 id="_2025-12-10-v7-7-0" tabindex="-1">2025.12.10 v7.7.0 <a class="header-anchor" href="#_2025-12-10-v7-7-0" aria-label="Permalink to &quot;2025.12.10 v7.7.0&quot;">​</a></h2><ol><li>Optimized <code>gitm copy</code></li><li>Upgraded dependencies</li></ol><h2 id="_2025-01-10-v7-6-0" tabindex="-1">2025.01.10 v7.6.0 <a class="header-anchor" href="#_2025-01-10-v7-6-0" aria-label="Permalink to &quot;2025.01.10 v7.6.0&quot;">​</a></h2><ol><li>Switched to <code>git switch</code></li><li>Optimized <code>gitm start</code> branch creation flow</li><li>Upgraded dependencies</li></ol><h2 id="_2024-08-08-v7-4-0" tabindex="-1">2024.08.08 v7.4.0 <a class="header-anchor" href="#_2024-08-08-v7-4-0" aria-label="Permalink to &quot;2024.08.08 v7.4.0&quot;">​</a></h2><ol><li><code>build-mp</code> added version type selection step, added baseInfo input</li></ol><h2 id="_2024-08-02-v7-3-0" tabindex="-1">2024.08.02 v7.3.0 <a class="header-anchor" href="#_2024-08-02-v7-3-0" aria-label="Permalink to &quot;2024.08.02 v7.3.0&quot;">​</a></h2><ol><li>Fixed <code>miniprogramToken</code> <code>miniprogramSession</code> required parameter issue</li></ol><h2 id="_2024-07-17-v7-2-0" tabindex="-1">2024.07.17 v7.2.0 <a class="header-anchor" href="#_2024-07-17-v7-2-0" aria-label="Permalink to &quot;2024.07.17 v7.2.0&quot;">​</a></h2><ol><li><code>miniprogramToken</code> <code>miniprogramSession</code> parameters now read from git config</li></ol><h2 id="_2024-06-18-v7-1-0" tabindex="-1">2024.06.18 v7.1.0 <a class="header-anchor" href="#_2024-06-18-v7-1-0" aria-label="Permalink to &quot;2024.06.18 v7.1.0&quot;">​</a></h2><ol><li>Added <code>--push</code> parameter to push target branch to remote after copy</li></ol><h2 id="_2024-05-10-v7-0-1" tabindex="-1">2024.05.10 v7.0.1 <a class="header-anchor" href="#_2024-05-10-v7-0-1" aria-label="Permalink to &quot;2024.05.10 v7.0.1&quot;">​</a></h2><ol><li>Fixed version control bug</li></ol><h2 id="_2024-05-10-v7-0-0" tabindex="-1">2024.05.10 v7.0.0 <a class="header-anchor" href="#_2024-05-10-v7-0-0" aria-label="Permalink to &quot;2024.05.10 v7.0.0&quot;">​</a></h2><ol><li>Refactored project, reorganized code structure</li><li>Added <code>build-mp</code> command for building miniprograms</li><li>Added <code>miniprogram</code> command for operating miniprograms</li><li><code>end</code> and <code>combine</code> commands now support batch operations</li><li><code>build</code> command refactored to optional parameters, project parameter no longer required</li><li>Build config now supports setting token in list</li><li>Cleaned up unnecessary dependencies</li><li>Upgraded dependencies</li></ol><h2 id="_2024-03-17-v6-4-0" tabindex="-1">2024.03.17 v6.4.0 <a class="header-anchor" href="#_2024-03-17-v6-4-0" aria-label="Permalink to &quot;2024.03.17 v6.4.0&quot;">​</a></h2><ol><li>Optimized prompts</li><li>Upgraded dependencies</li></ol><h2 id="_2024-03-01-v6-3-0" tabindex="-1">2024.03.01 v6.3.0 <a class="header-anchor" href="#_2024-03-01-v6-3-0" aria-label="Permalink to &quot;2024.03.01 v6.3.0&quot;">​</a></h2><ol><li><code>admin</code> and <code>combine</code> commands added build prompts</li><li>Upgraded dependencies</li></ol><h2 id="_2024-02-02-v6-2-0" tabindex="-1">2024.02.02 v6.2.0 <a class="header-anchor" href="#_2024-02-02-v6-2-0" aria-label="Permalink to &quot;2024.02.02 v6.2.0&quot;">​</a></h2><ol><li><code>build</code> command added <code>--confirm</code> parameter, skip confirmation when true</li></ol><h2 id="_2024-02-01-v6-1-0" tabindex="-1">2024.02.01 v6.1.0 <a class="header-anchor" href="#_2024-02-01-v6-1-0" aria-label="Permalink to &quot;2024.02.01 v6.1.0&quot;">​</a></h2><ol><li>Added parameter confirmation step to build command</li><li>Removed build parameter encoding</li><li>Upgraded dependencies</li></ol><h2 id="_2024-01-08-v6-0-0" tabindex="-1">2024.01.08 v6.0.0 <a class="header-anchor" href="#_2024-01-08-v6-0-0" aria-label="Permalink to &quot;2024.01.08 v6.0.0&quot;">​</a></h2><ol><li>Removed <code>server</code> and <code>ui</code> sub-projects</li><li>From v6.0.0, <code>token</code> is read from git config <code>user.token</code>, API no longer needs to return token</li><li>Deprecated <code>gitm merge</code> command</li><li>Upgraded dependencies</li></ol><h2 id="_2023-09-09-v5-3-0" tabindex="-1">2023.09.09 v5.3.0 <a class="header-anchor" href="#_2023-09-09-v5-3-0" aria-label="Permalink to &quot;2023.09.09 v5.3.0&quot;">​</a></h2><ol><li><code>combine</code>, <code>admin publish</code>, <code>build</code> commands added <code>--data</code> parameter for custom build parameters</li><li>Fixed <code>upgrade</code> not working with registry</li><li>Removed <code>compareVersion</code> method, using js-cool&#39;s compareVersion instead</li><li>Upgraded dependencies</li></ol><h2 id="_2023-08-16-v5-2-0" tabindex="-1">2023.08.16 v5.2.0 <a class="header-anchor" href="#_2023-08-16-v5-2-0" aria-label="Permalink to &quot;2023.08.16 v5.2.0&quot;">​</a></h2><ol><li>Fixed some issues</li><li>Upgraded dependencies</li></ol><h2 id="_2023-07-03-v5-1-6" tabindex="-1">2023.07.03 v5.1.6 <a class="header-anchor" href="#_2023-07-03-v5-1-6" aria-label="Permalink to &quot;2023.07.03 v5.1.6&quot;">​</a></h2><ol><li>Using <a href="https://github.com/saqqdy/os-lang" target="_blank" rel="noreferrer">os-lang</a> to get system language</li><li>Upgraded dependencies</li></ol><h2 id="_2023-05-31-v5-1-5" tabindex="-1">2023.05.31 v5.1.5 <a class="header-anchor" href="#_2023-05-31-v5-1-5" aria-label="Permalink to &quot;2023.05.31 v5.1.5&quot;">​</a></h2><ol><li>Fixed bugs and improved experience</li><li>Upgraded dependencies</li></ol><h2 id="_2023-03-26-v5-1-3" tabindex="-1">2023.03.26 v5.1.3 <a class="header-anchor" href="#_2023-03-26-v5-1-3" aria-label="Permalink to &quot;2023.03.26 v5.1.3&quot;">​</a></h2><ol><li>Using <a href="https://github.com/saqqdy/userdir" target="_blank" rel="noreferrer">userdir</a></li><li>Fixed type output</li><li>Upgraded dependencies</li></ol><h2 id="_2023-02-17-v5-1-1" tabindex="-1">2023.02.17 v5.1.1 <a class="header-anchor" href="#_2023-02-17-v5-1-1" aria-label="Permalink to &quot;2023.02.17 v5.1.1&quot;">​</a></h2><ol><li>Fixed <code>spawnSync</code> command parsing error</li><li>Version control now supports <code>prerelease</code>, <code>premajor</code>, <code>preminor</code>, <code>prepatch</code> versions</li><li>Build outputs gitmars type files</li><li>Upgraded dependencies</li></ol><h2 id="_2023-02-04-v5-0-0" tabindex="-1">2023.02.04 v5.0.0 <a class="header-anchor" href="#_2023-02-04-v5-0-0" aria-label="Permalink to &quot;2023.02.04 v5.0.0&quot;">​</a></h2><ol><li>Fully migrated to rollup v3.0</li><li>Added <code>versionControlType</code> config parameter for controlling forced update version type, pass false to disable</li><li>Upgraded dependencies, now using commander v10, reinstarter v2</li></ol><h2 id="_2023-01-14-v4-1-1" tabindex="-1">2023.01.14 v4.1.1 <a class="header-anchor" href="#_2023-01-14-v4-1-1" aria-label="Permalink to &quot;2023.01.14 v4.1.1&quot;">​</a></h2><ol><li>Upgraded dependencies</li></ol><h2 id="_2023-01-05-v4-1-0" tabindex="-1">2023.01.05 v4.1.0 <a class="header-anchor" href="#_2023-01-05-v4-1-0" aria-label="Permalink to &quot;2023.01.05 v4.1.0&quot;">​</a></h2><ol><li>Added <code>stringify</code> and <code>isWin32</code> methods to handle Windows environment script compatibility</li><li>Fixed <code>getIsMergedTargetBranch</code> compatibility issue on Windows</li><li>Upgraded spawn and spawnSync to handle Windows environment script compatibility</li></ol><h2 id="_2023-01-05-v4-0-4" tabindex="-1">2023.01.05 v4.0.4 <a class="header-anchor" href="#_2023-01-05-v4-0-4" aria-label="Permalink to &quot;2023.01.05 v4.0.4&quot;">​</a></h2><ol><li>Fixed <code>getIsMergedTargetBranch</code> compatibility issue on Windows</li></ol><h2 id="_2023-01-04-v4-0-3" tabindex="-1">2023.01.04 v4.0.3 <a class="header-anchor" href="#_2023-01-04-v4-0-3" aria-label="Permalink to &quot;2023.01.04 v4.0.3&quot;">​</a></h2><ol><li>Fixed <code>getIsMergedTargetBranch</code> compatibility issue on Windows</li><li>Downgraded os-local</li></ol><h2 id="_2023-01-02-v4-0-1" tabindex="-1">2023.01.02 v4.0.1 <a class="header-anchor" href="#_2023-01-02-v4-0-1" aria-label="Permalink to &quot;2023.01.02 v4.0.1&quot;">​</a></h2><ol><li>Started using <a href="https://github.com/saqqdy/reinstaller" target="_blank" rel="noreferrer">reinstaller</a></li></ol><h2 id="_2022-12-30-v4-0-0" tabindex="-1">2022.12.30 v4.0.0 <a class="header-anchor" href="#_2022-12-30-v4-0-0" aria-label="Permalink to &quot;2022.12.30 v4.0.0&quot;">​</a></h2><ol><li>Added multi-language support, currently supports <code>zh-CN</code> and <code>en-US</code></li><li><code>getIsMergedTargetBranch</code> method changed parameter passing, added strictly, changed default judgment method</li><li>Fully migrated to ESM specification, dropped support for node12 and below</li><li>Removed <code>msgUrl</code> from config</li><li>Fixed <code>update</code> command inaccurate merge detection bug</li><li>Moved global from core to gitmars</li><li>Refactored <code>copy</code> command to self-select commit records</li><li>Added <code>prune</code> method</li><li>Fixed <code>checkGitStatus</code> method bug</li><li>Removed default values for <code>lastet</code> and <code>limit</code></li><li>Upgraded dependencies</li></ol><h2 id="_2022-08-22-v3-3-5" tabindex="-1">2022.08.22 v3.3.5 <a class="header-anchor" href="#_2022-08-22-v3-3-5" aria-label="Permalink to &quot;2022.08.22 v3.3.5&quot;">​</a></h2><ol><li><code>combine</code>, <code>update</code>, <code>admin publish</code>, <code>admin update</code> commands added <code>--force</code> to force merge request</li></ol><h2 id="_2022-08-14-v3-3-4" tabindex="-1">2022.08.14 v3.3.4 <a class="header-anchor" href="#_2022-08-14-v3-3-4" aria-label="Permalink to &quot;2022.08.14 v3.3.4&quot;">​</a></h2><ol><li><code>postmsg</code> command now works outside git directory</li></ol><h2 id="_2022-08-12-v3-3-3" tabindex="-1">2022.08.12 v3.3.3 <a class="header-anchor" href="#_2022-08-12-v3-3-3" aria-label="Permalink to &quot;2022.08.12 v3.3.3&quot;">​</a></h2><ol><li>Fixed remaining <code>admin</code> command merge detection issues</li><li>Added <code>fetch</code> public method</li></ol><h2 id="_2022-08-12-v3-3-2" tabindex="-1">2022.08.12 v3.3.2 <a class="header-anchor" href="#_2022-08-12-v3-3-2" aria-label="Permalink to &quot;2022.08.12 v3.3.2&quot;">​</a></h2><ol><li>Fixed build process causing gitm-ui to not run</li></ol><h2 id="_2022-08-11-v3-3-1" tabindex="-1">2022.08.11 v3.3.1 <a class="header-anchor" href="#_2022-08-11-v3-3-1" aria-label="Permalink to &quot;2022.08.11 v3.3.1&quot;">​</a></h2><ol><li>Fixed <code>admin</code> command inaccurate merge detection</li></ol><h2 id="_2022-08-09-v3-3-0" tabindex="-1">2022.08.09 v3.3.0 <a class="header-anchor" href="#_2022-08-09-v3-3-0" aria-label="Permalink to &quot;2022.08.09 v3.3.0&quot;">​</a></h2><ol><li><code>combine</code>, <code>update</code>, <code>admin</code> commands added merge detection, no longer merge when not needed</li><li>Upgraded dependencies</li></ol><h2 id="_2022-07-19-v3-2-0" tabindex="-1">2022.07.19 v3.2.0 <a class="header-anchor" href="#_2022-07-19-v3-2-0" aria-label="Permalink to &quot;2022.07.19 v3.2.0&quot;">​</a></h2><ol><li>Fixed <code>gitm get</code> command not finding corresponding stash content</li><li>Fixed <code>gitm undo</code> command error</li><li>Improved typescript types</li></ol><h2 id="_2022-07-03-v3-1-0" tabindex="-1">2022.07.03 v3.1.0 <a class="header-anchor" href="#_2022-07-03-v3-1-0" aria-label="Permalink to &quot;2022.07.03 v3.1.0&quot;">​</a></h2><ol><li>Updated versionControl strategy, officially deprecated lite channel</li></ol><h2 id="_2022-06-12-v3-0-1" tabindex="-1">2022.06.12 v3.0.1 <a class="header-anchor" href="#_2022-06-12-v3-0-1" aria-label="Permalink to &quot;2022.06.12 v3.0.1&quot;">​</a></h2><ol><li>Improved experience</li><li>Fixed some issues</li></ol><h2 id="_2022-06-10-v3-0-0" tabindex="-1">2022.06.10 v3.0.0 <a class="header-anchor" href="#_2022-06-10-v3-0-0" aria-label="Permalink to &quot;2022.06.10 v3.0.0&quot;">​</a></h2><ol><li>Monorepo refactoring, split into <code>core</code>, <code>gitmars</code>, <code>server</code>, <code>ui</code>, <code>docs</code> sub-projects</li><li>Removed restriction that <code>alias</code> command only works in git projects</li><li>Upgraded dependencies</li></ol><h2 id="_2022-04-07-v2-18-1" tabindex="-1">2022.04.07 v2.18.1 <a class="header-anchor" href="#_2022-04-07-v2-18-1" aria-label="Permalink to &quot;2022.04.07 v2.18.1&quot;">​</a></h2><ol><li>Deleting branches now auto-executes <code>git remote prune origin</code> to clean records</li><li>Upgraded dependencies</li></ol><h2 id="_2022-03-24-v2-18-0" tabindex="-1">2022.03.24 v2.18.0 <a class="header-anchor" href="#_2022-03-24-v2-18-0" aria-label="Permalink to &quot;2022.03.24 v2.18.0&quot;">​</a></h2><ol><li>Added <code>gitm alias</code> command, init: <code>git alias init</code>, remove: <code>git alias remove</code></li><li>Added alias commands to use gitmars, can use <code>git mars xxx</code> or <code>git flow xxx</code>, both equivalent to <code>gitm xxx</code></li><li>Added <code>apis</code> to config, original <code>config.api</code> moved to <code>config.apis.userInfo</code></li><li>Added <code>config.apis.buildConfig</code> API config for reading build config, higher priority than <code>config.apolloConfig</code></li><li>Upgraded dependencies</li></ol><h2 id="_2022-02-24-v2-17-0" tabindex="-1">2022.02.24 v2.17.0 <a class="header-anchor" href="#_2022-02-24-v2-17-0" aria-label="Permalink to &quot;2022.02.24 v2.17.0&quot;">​</a></h2><ol><li>Added <code>level=3</code> reviewer permission, reviewers have merge permission and can execute <code>admin publish</code>, but unlike admins, reviewers push code to remote. Developer permission adjusted to 4</li></ol><h2 id="_2022-02-24-v2-16-6" tabindex="-1">2022.02.24 v2.16.6 <a class="header-anchor" href="#_2022-02-24-v2-16-6" aria-label="Permalink to &quot;2022.02.24 v2.16.6&quot;">​</a></h2><ol><li>Optimized project name extraction logic</li></ol><h2 id="_2021-12-27-v2-16-5" tabindex="-1">2021.12.27 v2.16.5 <a class="header-anchor" href="#_2021-12-27-v2-16-5" aria-label="Permalink to &quot;2021.12.27 v2.16.5&quot;">​</a></h2><ol><li><code>approve</code> and <code>review</code> commands added <code>--quiet</code>, removed <code>--postmsg</code>, now send messages by default</li></ol><h2 id="_2021-12-27-v2-16-4" tabindex="-1">2021.12.27 v2.16.4 <a class="header-anchor" href="#_2021-12-27-v2-16-4" aria-label="Permalink to &quot;2021.12.27 v2.16.4&quot;">​</a></h2><ol><li>Extended <code>request</code> method to support gzip</li></ol><h2 id="_2021-12-23-v2-16-3" tabindex="-1">2021.12.23 v2.16.3 <a class="header-anchor" href="#_2021-12-23-v2-16-3" aria-label="Permalink to &quot;2021.12.23 v2.16.3&quot;">​</a></h2><ol><li>Optimized <code>approve</code> command batch operation experience</li></ol><h2 id="_2021-12-23-v2-16-2" tabindex="-1">2021.12.23 v2.16.2 <a class="header-anchor" href="#_2021-12-23-v2-16-2" aria-label="Permalink to &quot;2021.12.23 v2.16.2&quot;">​</a></h2><ol><li><code>approve</code> command now shows comment count</li><li>Adjusted prompts</li></ol><h2 id="_2021-12-20-v2-16-0" tabindex="-1">2021.12.20 v2.16.0 <a class="header-anchor" href="#_2021-12-20-v2-16-0" aria-label="Permalink to &quot;2021.12.20 v2.16.0&quot;">​</a></h2><h3 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h3><ol><li>Added <code>approve</code> command for approving remote merge requests, supports diff preview, added <code>gitm admin approve</code> command</li><li>Added <code>review</code> command for code review, submits review records</li><li>Extended <code>request</code> method to support <code>PUT</code> and <code>DELETE</code></li></ol><h3 id="improvements" tabindex="-1">Improvements <a class="header-anchor" href="#improvements" aria-label="Permalink to &quot;Improvements&quot;">​</a></h3><ol><li>Fixed <code>service</code> cache issue</li><li>Optimized documentation</li></ol><h2 id="_2021-12-14-v2-15-4" tabindex="-1">2021.12.14 v2.15.4 <a class="header-anchor" href="#_2021-12-14-v2-15-4" aria-label="Permalink to &quot;2021.12.14 v2.15.4&quot;">​</a></h2><ol><li>Added <code>status</code> command to view current branch status</li></ol><h2 id="_2021-12-13-v2-15-3" tabindex="-1">2021.12.13 v2.15.3 <a class="header-anchor" href="#_2021-12-13-v2-15-3" aria-label="Permalink to &quot;2021.12.13 v2.15.3&quot;">​</a></h2><ol><li><code>log</code> command added <code>--json</code> parameter for JSON output, defaults to table</li></ol><h2 id="_2021-12-12-v2-15-2" tabindex="-1">2021.12.12 v2.15.2 <a class="header-anchor" href="#_2021-12-12-v2-15-2" aria-label="Permalink to &quot;2021.12.12 v2.15.2&quot;">​</a></h2><ol><li>Added <code>debug</code> method, enable debug functionality</li></ol><h2 id="_2021-12-11-v2-15-1" tabindex="-1">2021.12.11 v2.15.1 <a class="header-anchor" href="#_2021-12-11-v2-15-1" aria-label="Permalink to &quot;2021.12.11 v2.15.1&quot;">​</a></h2><ol><li><code>gitm ui</code> now supports <code>undo</code> and <code>redo</code></li><li><code>gitm go</code> now supports <code>undo</code> and <code>redo</code></li></ol><h2 id="_2021-12-06-v2-15-0" tabindex="-1">2021.12.06 v2.15.0 <a class="header-anchor" href="#_2021-12-06-v2-15-0" aria-label="Permalink to &quot;2021.12.06 v2.15.0&quot;">​</a></h2><h3 id="features-1" tabindex="-1">Features <a class="header-anchor" href="#features-1" aria-label="Permalink to &quot;Features&quot;">​</a></h3><ol><li>Switched to native script executor for better performance, replacing shelljs <code>sh.exec</code></li><li>Added <code>undo</code> command for reverting code</li><li>Added <code>redo</code> command for restoring reverted code</li><li>Optimized <code>cleanbranch</code> command flow, can select branches to clean after preview</li><li><code>undo</code> command added <code>--no-merges</code>, <code>--limit</code>, <code>--lastet</code>, <code>--calc</code>, <code>--calcAll</code> parameters</li><li><code>log</code> command added <code>--no-merges</code> parameter to exclude merge records</li><li>Replaced <code>sh.exit</code> with <code>process.exit</code></li></ol><h3 id="improvements-1" tabindex="-1">Improvements <a class="header-anchor" href="#improvements-1" aria-label="Permalink to &quot;Improvements&quot;">​</a></h3><ol><li>Optimized <code>git log</code> reading experience</li><li>Added <code>echo</code>, <code>gitLogsFormatter</code>, <code>revertCache</code>, <code>writeFileSync</code> methods</li><li>Removed <code>filterBranch</code> method</li><li>Improved <code>typescript</code> types</li></ol><h2 id="_2021-12-02-v2-14-6" tabindex="-1">2021.12.02 v2.14.6 <a class="header-anchor" href="#_2021-12-02-v2-14-6" aria-label="Permalink to &quot;2021.12.02 v2.14.6&quot;">​</a></h2><ol><li>Replaced <code>curl</code> scripts for build and group message, handled win7 curl compatibility issue</li></ol><h2 id="_2021-12-02-v2-14-5" tabindex="-1">2021.12.02 v2.14.5 <a class="header-anchor" href="#_2021-12-02-v2-14-5" aria-label="Permalink to &quot;2021.12.02 v2.14.5&quot;">​</a></h2><ol><li>Extended <code>queue</code> method to support promise functions</li><li>Replaced <code>curl</code> script for creating remote merge requests, handled win7 curl compatibility issue</li><li>Fixed script queue <code>continue</code> cache save failure issue</li><li>Fixed <code>circular dependency</code> issue</li></ol><h2 id="_2021-11-30-v2-14-4" tabindex="-1">2021.11.30 v2.14.4 <a class="header-anchor" href="#_2021-11-30-v2-14-4" aria-label="Permalink to &quot;2021.11.30 v2.14.4&quot;">​</a></h2><ol><li>Replaced <code>curl</code> scripts, handled win7 curl compatibility issue</li><li>Encapsulated <code>request</code> method</li></ol><h2 id="_2021-11-28-v2-14-3" tabindex="-1">2021.11.28 v2.14.3 <a class="header-anchor" href="#_2021-11-28-v2-14-3" aria-label="Permalink to &quot;2021.11.28 v2.14.3&quot;">​</a></h2><ol><li><code>cleanbranch</code> command no longer auto-switches branches</li><li>Optimized <code>log</code> command experience</li></ol><h2 id="_2021-11-27-v2-14-2" tabindex="-1">2021.11.27 v2.14.2 <a class="header-anchor" href="#_2021-11-27-v2-14-2" aria-label="Permalink to &quot;2021.11.27 v2.14.2&quot;">​</a></h2><ol><li>Optimized <code>cleanbranch</code> command prompts</li><li><code>ui</code> interface now supports <code>cleanbranch</code>/<code>admin publish</code>/<code>clean</code>/<code>log</code> commands</li></ol><h2 id="_2021-11-26-v2-14-1" tabindex="-1">2021.11.26 v2.14.1 <a class="header-anchor" href="#_2021-11-26-v2-14-1" aria-label="Permalink to &quot;2021.11.26 v2.14.1&quot;">​</a></h2><ol><li>Optimized code</li><li>Changed license to <code>GPL-3.0</code></li></ol><h2 id="_2021-11-26-v2-14-0" tabindex="-1">2021.11.26 v2.14.0 <a class="header-anchor" href="#_2021-11-26-v2-14-0" aria-label="Permalink to &quot;2021.11.26 v2.14.0&quot;">​</a></h2><ol><li>Refactored core code</li><li><code>cleanbranch</code> command removed restriction on secondary branches only</li></ol><h2 id="_2021-11-22-v2-13-9" tabindex="-1">2021.11.22 v2.13.9 <a class="header-anchor" href="#_2021-11-22-v2-13-9" aria-label="Permalink to &quot;2021.11.22 v2.13.9&quot;">​</a></h2><ol><li><code>cleanbranch</code> command added <code>--key</code> parameter for filter keywords</li><li><code>cleanbranch</code> command added <code>--include</code> parameter for regex branch filtering</li><li><code>cleanbranch</code> command changed <code>--except</code> to <code>--exclude</code>, usage unchanged</li></ol><h2 id="_2021-11-21-v2-13-8" tabindex="-1">2021.11.21 v2.13.8 <a class="header-anchor" href="#_2021-11-21-v2-13-8" aria-label="Permalink to &quot;2021.11.21 v2.13.8&quot;">​</a></h2><ol><li>Optimized script execution prompts, added <code>processing</code> status</li><li><code>clean</code> command no longer cleans gitmars config, <code>--force</code> now deletes execution cache</li><li>Optimized <code>upgrade</code> command flow</li><li>Optimized <code>clean</code> command experience</li></ol><h2 id="_2021-11-20-v2-13-7" tabindex="-1">2021.11.20 v2.13.7 <a class="header-anchor" href="#_2021-11-20-v2-13-7" aria-label="Permalink to &quot;2021.11.20 v2.13.7&quot;">​</a></h2><ol><li><code>cleanbranch</code> command added <code>branches</code> parameter to specify branches to clean, multiple branches separated by spaces</li><li><code>cleanbranch</code> command added <code>--target</code> parameter for target branches to check merge status, multiple branches separated by commas, default: develop,release</li><li>Optimized prompts</li></ol><h2 id="_2021-11-20-v2-13-6" tabindex="-1">2021.11.20 v2.13.6 <a class="header-anchor" href="#_2021-11-20-v2-13-6" aria-label="Permalink to &quot;2021.11.20 v2.13.6&quot;">​</a></h2><ol><li><code>cleanbranch</code> command compatible with older git versions</li></ol><h2 id="_2021-11-19-v2-13-5" tabindex="-1">2021.11.19 v2.13.5 <a class="header-anchor" href="#_2021-11-19-v2-13-5" aria-label="Permalink to &quot;2021.11.19 v2.13.5&quot;">​</a></h2><ol><li><code>cleanbranch</code> command added <code>--confirm</code> parameter, skip confirmation when true</li><li>Fixed inaccurate detection issue</li></ol><h2 id="_2021-11-19-v2-13-3" tabindex="-1">2021.11.19 v2.13.3 <a class="header-anchor" href="#_2021-11-19-v2-13-3" aria-label="Permalink to &quot;2021.11.19 v2.13.3&quot;">​</a></h2><ol><li><code>cleanbranch</code> command removed permission control</li><li><code>go</code> command now supports cleanbranch</li></ol><h2 id="_2021-11-19-v2-13-2" tabindex="-1">2021.11.19 v2.13.2 <a class="header-anchor" href="#_2021-11-19-v2-13-2" aria-label="Permalink to &quot;2021.11.19 v2.13.2&quot;">​</a></h2><ol><li>Improved <code>searchBranches</code> method, removed <code>local</code> parameter</li><li>Corrected branchs spelling error</li></ol><h2 id="_2021-11-19-v2-13-1" tabindex="-1">2021.11.19 v2.13.1 <a class="header-anchor" href="#_2021-11-19-v2-13-1" aria-label="Permalink to &quot;2021.11.19 v2.13.1&quot;">​</a></h2><ol><li><code>cleanbranch</code> command added <code>--list</code> parameter to preview before deleting</li><li>Optimized <code>cleanbranch</code> command flow with animations and prompts</li><li><code>cleanbranch</code> added short command <code>gitm clb</code></li><li><code>cleanbranch</code> command added permission control, only admin level and above (level &lt; 3) can execute</li><li><code>cleanbranch</code> command auto-switches branches before execution</li></ol><h2 id="_2021-11-18-v2-13-0" tabindex="-1">2021.11.18 v2.13.0 <a class="header-anchor" href="#_2021-11-18-v2-13-0" aria-label="Permalink to &quot;2021.11.18 v2.13.0&quot;">​</a></h2><ol><li>Added <code>cleanbranch</code> command to clean merged feature branches</li><li>Improved <code>searchBranches</code> method, supports multi-type search, added <code>local</code> parameter and <code>exclude</code> regex</li></ol><h2 id="_2021-11-18-v2-12-8" tabindex="-1">2021.11.18 v2.12.8 <a class="header-anchor" href="#_2021-11-18-v2-12-8" aria-label="Permalink to &quot;2021.11.18 v2.12.8&quot;">​</a></h2><ol><li><code>go</code> command now supports clean method</li><li>Optimized <code>clean</code> command flow</li></ol><h2 id="_2021-11-17-v2-12-7" tabindex="-1">2021.11.17 v2.12.7 <a class="header-anchor" href="#_2021-11-17-v2-12-7" aria-label="Permalink to &quot;2021.11.17 v2.12.7&quot;">​</a></h2><ol><li>Fixed <code>start</code> command code not found when creating branch from tag</li></ol><h2 id="_2021-11-16-v2-12-6" tabindex="-1">2021.11.16 v2.12.6 <a class="header-anchor" href="#_2021-11-16-v2-12-6" aria-label="Permalink to &quot;2021.11.16 v2.12.6&quot;">​</a></h2><ol><li>Build config now supports saving multiple configs</li><li><code>clean</code> command now cleans <code>packageInfo</code> cache</li></ol><h2 id="_2021-11-14-v2-12-5" tabindex="-1">2021.11.14 v2.12.5 <a class="header-anchor" href="#_2021-11-14-v2-12-5" aria-label="Permalink to &quot;2021.11.14 v2.12.5&quot;">​</a></h2><ol><li><code>continue</code> command now checks for forgotten commit code before execution</li></ol><h2 id="_2021-11-12-v2-12-3" tabindex="-1">2021.11.12 v2.12.3 <a class="header-anchor" href="#_2021-11-12-v2-12-3" aria-label="Permalink to &quot;2021.11.12 v2.12.3&quot;">​</a></h2><ol><li>Fixed Windows environment <code>UI</code> interface <code>xterm</code> runtime error</li></ol><h2 id="_2021-11-11-v2-12-2" tabindex="-1">2021.11.11 v2.12.2 <a class="header-anchor" href="#_2021-11-11-v2-12-2" aria-label="Permalink to &quot;2021.11.11 v2.12.2&quot;">​</a></h2><ol><li>Build now supports multiple apps separated by commas</li></ol><h2 id="_2021-11-11-v2-12-1" tabindex="-1">2021.11.11 v2.12.1 <a class="header-anchor" href="#_2021-11-11-v2-12-1" aria-label="Permalink to &quot;2021.11.11 v2.12.1&quot;">​</a></h2><ol><li><code>copy</code> command removed push action</li></ol><h2 id="_2021-11-10-v2-12-0" tabindex="-1">2021.11.10 v2.12.0 <a class="header-anchor" href="#_2021-11-10-v2-12-0" aria-label="Permalink to &quot;2021.11.10 v2.12.0&quot;">​</a></h2><h3 id="features-2" tabindex="-1">Features <a class="header-anchor" href="#features-2" aria-label="Permalink to &quot;Features&quot;">​</a></h3><ol><li><code>combine</code>, <code>end</code>, <code>start</code>, <code>update</code> commands added version detection to solve fragmentation issue</li><li>Adjusted <code>apollo</code> config caching scheme</li><li>Added <code>packageInfo</code> cache</li></ol><h3 id="improvements-2" tabindex="-1">Improvements <a class="header-anchor" href="#improvements-2" aria-label="Permalink to &quot;Improvements&quot;">​</a></h3><ol><li>Improved typescript types</li><li>Optimized <code>apollo</code> config reading scheme</li></ol><h2 id="_2021-11-08-v2-11-1" tabindex="-1">2021.11.08 v2.11.1 <a class="header-anchor" href="#_2021-11-08-v2-11-1" aria-label="Permalink to &quot;2021.11.08 v2.11.1&quot;">​</a></h2><ol><li>Fixed inaccurate <code>dev</code> branch merge detection</li></ol><h2 id="_2021-11-08-v2-11-0" tabindex="-1">2021.11.08 v2.11.0 <a class="header-anchor" href="#_2021-11-08-v2-11-0" aria-label="Permalink to &quot;2021.11.08 v2.11.0&quot;">​</a></h2><h3 id="features-3" tabindex="-1">Features <a class="header-anchor" href="#features-3" aria-label="Permalink to &quot;Features&quot;">​</a></h3><ol><li>Added global config <code>descriptionValidator</code> for validating commit reason description, supports regex and regex string</li><li><code>combine</code>, <code>end</code>, <code>admin.publish</code>, <code>admin.update</code> methods added <code>--description</code> parameter with validation</li></ol><h3 id="improvements-3" tabindex="-1">Improvements <a class="header-anchor" href="#improvements-3" aria-label="Permalink to &quot;Improvements&quot;">​</a></h3><ol><li>Extracted shell script generation method</li></ol><h2 id="_2021-11-06-v2-10-2" tabindex="-1">2021.11.06 v2.10.2 <a class="header-anchor" href="#_2021-11-06-v2-10-2" aria-label="Permalink to &quot;2021.11.06 v2.10.2&quot;">​</a></h2><h3 id="features-4" tabindex="-1">Features <a class="header-anchor" href="#features-4" aria-label="Permalink to &quot;Features&quot;">​</a></h3><ol><li><code>upgrade</code> command added <code>--registry</code> and <code>--client</code> parameters for specifying mirror address and client</li></ol><h2 id="_2021-11-05-v2-10-1" tabindex="-1">2021.11.05 v2.10.1 <a class="header-anchor" href="#_2021-11-05-v2-10-1" aria-label="Permalink to &quot;2021.11.05 v2.10.1&quot;">​</a></h2><h3 id="improvements-4" tabindex="-1">Improvements <a class="header-anchor" href="#improvements-4" aria-label="Permalink to &quot;Improvements&quot;">​</a></h3><ol><li><code>combine</code> and <code>end</code> commands now use remote branches by default to check if merged to dev</li></ol><h2 id="_2021-11-02-v2-10-0" tabindex="-1">2021.11.02 v2.10.0 <a class="header-anchor" href="#_2021-11-02-v2-10-0" aria-label="Permalink to &quot;2021.11.02 v2.10.0&quot;">​</a></h2><h3 id="features-5" tabindex="-1">Features <a class="header-anchor" href="#features-5" aria-label="Permalink to &quot;Features&quot;">​</a></h3><ol><li><code>copy</code> command usage adjusted, from parameter changed to <code>--source</code>. Usage: <code>gitm copy [commitid...]</code> or <code>gitm copy [-s --source [source]] [-k --key [keyword]] [-a --author [author]]</code></li><li><code>copy</code> command now requires <code>--key</code> parameter for fuzzy batch copy, minimum 3 characters</li></ol><h3 id="improvements-5" tabindex="-1">Improvements <a class="header-anchor" href="#improvements-5" aria-label="Permalink to &quot;Improvements&quot;">​</a></h3><ol><li><code>continue</code> command now cleans execution cache after successful execution</li></ol><h2 id="_2021-10-31-v2-9-7" tabindex="-1">2021.10.31 v2.9.7 <a class="header-anchor" href="#_2021-10-31-v2-9-7" aria-label="Permalink to &quot;2021.10.31 v2.9.7&quot;">​</a></h2><ol><li>Adjusted database storage location to prevent data loss after upgrade</li><li><code>log</code> command now exposes more log details</li></ol><h2 id="_2021-10-30-v2-9-6" tabindex="-1">2021.10.30 v2.9.6 <a class="header-anchor" href="#_2021-10-30-v2-9-6" aria-label="Permalink to &quot;2021.10.30 v2.9.6&quot;">​</a></h2><ol><li><code>end</code> command now intelligently determines whether to merge code, won&#39;t merge when not needed without <code>--no-combine</code></li><li><code>getIsMergedDevBranch</code> changed to <code>getIsMergedTargetBranch</code>, added <code>remote</code> parameter</li><li>Abstracted <code>getIsBranchOrCommitExist</code> method for checking branch or commit existence</li></ol><h2 id="_2021-10-29-v2-9-5" tabindex="-1">2021.10.29 v2.9.5 <a class="header-anchor" href="#_2021-10-29-v2-9-5" aria-label="Permalink to &quot;2021.10.29 v2.9.5&quot;">​</a></h2><ol><li>Optimized <code>getIsUpdatedInTime</code> method detection strategy</li></ol><h2 id="_2021-10-28-v2-9-4" tabindex="-1">2021.10.28 v2.9.4 <a class="header-anchor" href="#_2021-10-28-v2-9-4" aria-label="Permalink to &quot;2021.10.28 v2.9.4&quot;">​</a></h2><ol><li>Added <code>nameValidator</code> config parameter for validating branch name, supports regex and regex string</li><li>Branch name now supports slashes: <code>gitm start feature saqqdy/10000</code></li></ol><h2 id="_2021-10-28-v2-9-3" tabindex="-1">2021.10.28 v2.9.3 <a class="header-anchor" href="#_2021-10-28-v2-9-3" aria-label="Permalink to &quot;2021.10.28 v2.9.3&quot;">​</a></h2><ol><li>Fixed custom port <code>UI</code> startup not working</li></ol><h2 id="_2021-10-25-v2-9-2" tabindex="-1">2021.10.25 v2.9.2 <a class="header-anchor" href="#_2021-10-25-v2-9-2" aria-label="Permalink to &quot;2021.10.25 v2.9.2&quot;">​</a></h2><ol><li><code>ui</code> command added <code>--port</code> parameter for custom port number</li></ol><h2 id="_2021-10-24-v2-9-1" tabindex="-1">2021.10.24 v2.9.1 <a class="header-anchor" href="#_2021-10-24-v2-9-1" aria-label="Permalink to &quot;2021.10.24 v2.9.1&quot;">​</a></h2><ol><li>Upgraded dependencies</li><li>Improved documentation</li></ol><h2 id="_2021-10-23-v2-9-0" tabindex="-1">2021.10.23 v2.9.0 <a class="header-anchor" href="#_2021-10-23-v2-9-0" aria-label="Permalink to &quot;2021.10.23 v2.9.0&quot;">​</a></h2><ol><li><code>go</code> command added <code>command</code> parameter to directly enter corresponding command</li><li>Improved help prompts for each command</li><li>Improved type definitions</li></ol><h2 id="_2021-10-22-v2-8-9" tabindex="-1">2021.10.22 v2.8.9 <a class="header-anchor" href="#_2021-10-22-v2-8-9" aria-label="Permalink to &quot;2021.10.22 v2.8.9&quot;">​</a></h2><ol><li>Improved UI interface branch creation functionality</li><li>Optimized user experience</li></ol><h2 id="_2021-10-22-v2-8-8" tabindex="-1">2021.10.22 v2.8.8 <a class="header-anchor" href="#_2021-10-22-v2-8-8" aria-label="Permalink to &quot;2021.10.22 v2.8.8&quot;">​</a></h2><ol><li>Fixed cross-platform script escaping issue</li></ol><h2 id="_2021-10-22-v2-8-6" tabindex="-1">2021.10.22 v2.8.6 <a class="header-anchor" href="#_2021-10-22-v2-8-6" aria-label="Permalink to &quot;2021.10.22 v2.8.6&quot;">​</a></h2><ol><li><code>gitm ui</code> now auto-opens browser</li></ol><h2 id="_2021-10-21-v2-8-5" tabindex="-1">2021.10.21 v2.8.5 <a class="header-anchor" href="#_2021-10-21-v2-8-5" aria-label="Permalink to &quot;2021.10.21 v2.8.5&quot;">​</a></h2><ol><li>Fixed inaccurate <code>dev</code> merge detection</li></ol><h2 id="_2021-10-20-v2-8-3" tabindex="-1">2021.10.20 v2.8.3 <a class="header-anchor" href="#_2021-10-20-v2-8-3" aria-label="Permalink to &quot;2021.10.20 v2.8.3&quot;">​</a></h2><ol><li>Fixed <code>dev</code> merge detection bug</li><li>Fixed method export error</li></ol><h2 id="_2021-10-20-v2-8-0" tabindex="-1">2021.10.20 v2.8.0 <a class="header-anchor" href="#_2021-10-20-v2-8-0" aria-label="Permalink to &quot;2021.10.20 v2.8.0&quot;">​</a></h2><ol><li><code>start</code> command now supports creating bugfix branch from tag</li></ol><h2 id="_2021-10-19-v2-7-0" tabindex="-1">2021.10.19 v2.7.0 <a class="header-anchor" href="#_2021-10-19-v2-7-0" aria-label="Permalink to &quot;2021.10.19 v2.7.0&quot;">​</a></h2><ol><li>Corrected <code>log</code> and <code>hook</code> command parameter error: changed <code>latest</code> to <code>lastet</code></li><li><code>combine</code> command added <code>dev</code> branch sync check, won&#39;t allow prod merge if not synced</li><li><code>combine</code> command added check for not syncing main branch code for over 1 week</li></ol><h2 id="_2021-10-18-v2-6-5" tabindex="-1">2021.10.18 v2.6.5 <a class="header-anchor" href="#_2021-10-18-v2-6-5" aria-label="Permalink to &quot;2021.10.18 v2.6.5&quot;">​</a></h2><ol><li>Optimized <code>ui</code> user experience</li><li><code>end</code> command now has checks when deleting branches</li><li>Fixed some config bugs</li></ol><h2 id="_2021-10-18-v2-6-4" tabindex="-1">2021.10.18 v2.6.4 <a class="header-anchor" href="#_2021-10-18-v2-6-4" aria-label="Permalink to &quot;2021.10.18 v2.6.4&quot;">​</a></h2><ol><li>Fixed <code>end</code> command <code>--no-combine</code> parameter not working</li></ol><h2 id="_2021-10-17-v2-6-3" tabindex="-1">2021.10.17 v2.6.3 <a class="header-anchor" href="#_2021-10-17-v2-6-3" aria-label="Permalink to &quot;2021.10.17 v2.6.3&quot;">​</a></h2><ol><li>Optimized <code>ui</code> interface, split task and workflow into 2 Terminals</li><li>Optimized experience and styles</li></ol><h2 id="_2021-10-16-v2-6-2" tabindex="-1">2021.10.16 v2.6.2 <a class="header-anchor" href="#_2021-10-16-v2-6-2" aria-label="Permalink to &quot;2021.10.16 v2.6.2&quot;">​</a></h2><ol><li>Fixed several <code>ui</code> bugs</li></ol><h2 id="_2021-10-15-v2-6-1" tabindex="-1">2021.10.15 v2.6.1 <a class="header-anchor" href="#_2021-10-15-v2-6-1" aria-label="Permalink to &quot;2021.10.15 v2.6.1&quot;">​</a></h2><ol><li><code>end</code> command added <code>--as-feature</code> and <code>--no-combine</code> parameters</li><li>Upgraded dependencies</li><li>Optimized code</li></ol><h2 id="_2021-09-17-v2-6-0" tabindex="-1">2021.09.17 v2.6.0 <a class="header-anchor" href="#_2021-09-17-v2-6-0" aria-label="Permalink to &quot;2021.09.17 v2.6.0&quot;">​</a></h2><ol><li>Refactored <code>server</code> with typescript</li><li>Optimized <code>get</code> command</li></ol><h2 id="_2021-09-12-v2-5-1" tabindex="-1">2021.09.12 v2.5.1 <a class="header-anchor" href="#_2021-09-12-v2-5-1" aria-label="Permalink to &quot;2021.09.12 v2.5.1&quot;">​</a></h2><ol><li><code>upgrade</code> command <code>version</code> parameter now supports tag names: <code>alpha</code>, <code>beta</code>, <code>release</code>, <code>lite</code>, <code>latest</code>, <code>next</code>, <code>x.x.x</code>, default <code>latest</code></li></ol><h2 id="_2021-09-12-v2-5-0" tabindex="-1">2021.09.12 v2.5.0 <a class="header-anchor" href="#_2021-09-12-v2-5-0" aria-label="Permalink to &quot;2021.09.12 v2.5.0&quot;">​</a></h2><ol><li>Refactored project with typescript</li><li>Cleaned <code>bin</code> directory to reduce npm package size</li><li>Fixed <code>upgrade</code> execution error</li></ol><h2 id="_2021-09-04-v2-4-0" tabindex="-1">2021.09.04 v2.4.0 <a class="header-anchor" href="#_2021-09-04-v2-4-0" aria-label="Permalink to &quot;2021.09.04 v2.4.0&quot;">​</a></h2><ol><li>Migrated <code>gitm ui</code> to <code>vue3+vite+typescript</code> framework</li><li>Cleaned <code>static</code> directory to reduce npm package size</li></ol><h2 id="_2021-08-28-v2-3-0" tabindex="-1">2021.08.28 v2.3.0 <a class="header-anchor" href="#_2021-08-28-v2-3-0" aria-label="Permalink to &quot;2021.08.28 v2.3.0&quot;">​</a></h2><ol><li>Adjusted <code>link</code>/<code>unlink</code> usage</li><li>Reduced npm package size</li></ol><h2 id="_2021-08-25-v2-2-10" tabindex="-1">2021.08.25 v2.2.10 <a class="header-anchor" href="#_2021-08-25-v2-2-10" aria-label="Permalink to &quot;2021.08.25 v2.2.10&quot;">​</a></h2><ol><li>Adjusted build config storage directory</li><li>Added runtime environment checks to commands</li><li>Upgraded dependencies</li></ol><h2 id="_2021-08-20-v2-2-9" tabindex="-1">2021.08.20 v2.2.9 <a class="header-anchor" href="#_2021-08-20-v2-2-9" aria-label="Permalink to &quot;2021.08.20 v2.2.9&quot;">​</a></h2><ol><li><code>gitm end</code> command now deletes remote branch</li><li><code>branch</code> command now supports deleting remote branches</li><li><code>go</code> command now supports <code>link</code>/<code>unlink</code>/<code>postmsg</code></li></ol><h2 id="_2021-08-10-v2-2-8" tabindex="-1">2021.08.10 v2.2.8 <a class="header-anchor" href="#_2021-08-10-v2-2-8" aria-label="Permalink to &quot;2021.08.10 v2.2.8&quot;">​</a></h2><ol><li>Fixed <code>postmsg</code> Chinese encoding issue</li></ol><h2 id="_2021-08-10-v2-2-7" tabindex="-1">2021.08.10 v2.2.7 <a class="header-anchor" href="#_2021-08-10-v2-2-7" aria-label="Permalink to &quot;2021.08.10 v2.2.7&quot;">​</a></h2><ol><li>Send group message notification when making git operation requests</li><li><code>postmsg</code> command supports custom message notification <code>url</code></li></ol><h2 id="_2021-08-05-v2-2-6" tabindex="-1">2021.08.05 v2.2.6 <a class="header-anchor" href="#_2021-08-05-v2-2-6" aria-label="Permalink to &quot;2021.08.05 v2.2.6&quot;">​</a></h2><ol><li>Fixed <code>windows</code> merge request failure issue</li></ol><h2 id="_2021-07-22-v2-2-5" tabindex="-1">2021.07.22 v2.2.5 <a class="header-anchor" href="#_2021-07-22-v2-2-5" aria-label="Permalink to &quot;2021.07.22 v2.2.5&quot;">​</a></h2><ol><li>Fixed build issue without merge permission</li><li>Deprecated <code>babel</code>, using <code>esbuild</code></li><li>Cleaned unnecessary dependencies, fixed code issues</li></ol><h2 id="_2021-07-15-v2-2-4" tabindex="-1">2021.07.15 v2.2.4 <a class="header-anchor" href="#_2021-07-15-v2-2-4" aria-label="Permalink to &quot;2021.07.15 v2.2.4&quot;">​</a></h2><ol><li>Fixed build being triggered without merge permission</li></ol><h2 id="_2021-07-04-v2-2-3" tabindex="-1">2021.07.04 v2.2.3 <a class="header-anchor" href="#_2021-07-04-v2-2-3" aria-label="Permalink to &quot;2021.07.04 v2.2.3&quot;">​</a></h2><ol><li><code>gitm update</code> supports <code>--all</code> to update all local branches at once</li><li><code>gitm update</code> now uses <code>merge</code> by default, added <code>--use-rebase</code> parameter</li><li>Added branch search method for better performance</li></ol><h2 id="_2021-05-29-v2-2-2" tabindex="-1">2021.05.29 v2.2.2 <a class="header-anchor" href="#_2021-05-29-v2-2-2" aria-label="Permalink to &quot;2021.05.29 v2.2.2&quot;">​</a></h2><ol><li>Organized documentation</li></ol><h2 id="_2021-05-15-v2-2-1" tabindex="-1">2021.05.15 v2.2.1 <a class="header-anchor" href="#_2021-05-15-v2-2-1" aria-label="Permalink to &quot;2021.05.15 v2.2.1&quot;">​</a></h2><ol><li>Organized code</li></ol><h2 id="_2021-05-15-v2-2-0" tabindex="-1">2021.05.15 v2.2.0 <a class="header-anchor" href="#_2021-05-15-v2-2-0" aria-label="Permalink to &quot;2021.05.15 v2.2.0&quot;">​</a></h2><ol><li>Optimized <code>gitmars UI</code> interface startup</li><li>Upgraded dependencies</li><li>Fixed some bugs</li></ol><h2 id="_2021-05-03-v2-1-0" tabindex="-1">2021.05.03 v2.1.0 <a class="header-anchor" href="#_2021-05-03-v2-1-0" aria-label="Permalink to &quot;2021.05.03 v2.1.0&quot;">​</a></h2><ol><li><code>go</code> command now supports <code>admin.create</code>/<code>admin.update</code>/<code>admin.clean</code>/<code>branch</code>/<code>get</code>/<code>save</code>/<code>copy</code>/<code>revert</code></li><li>Parameter validation now uses sub-option config first</li></ol><h2 id="_2021-04-27-v2-0-3" tabindex="-1">2021.04.27 v2.0.3 <a class="header-anchor" href="#_2021-04-27-v2-0-3" aria-label="Permalink to &quot;2021.04.27 v2.0.3&quot;">​</a></h2><ol><li>Added <code>admin</code> command auto-creates <code>merge</code> request, optimized logic</li></ol><h2 id="_2021-03-27-v2-0-2" tabindex="-1">2021.03.27 v2.0.2 <a class="header-anchor" href="#_2021-03-27-v2-0-2" aria-label="Permalink to &quot;2021.03.27 v2.0.2&quot;">​</a></h2><ol><li>Added <code>gitm ui</code> command to start UI interface</li><li>Added auto merge request for no git permission, need to configure <code>api</code>, <code>gitHost</code>, <code>gitID</code></li><li>Upgraded <code>checkBranch</code>, <code>searchBranches</code>, <code>getCurrentBranch</code> methods for better performance</li><li>Removed forced api config</li><li><code>git config</code> and <code>git init</code> now support <code>api</code>/<code>gitHost</code>/<code>gitID</code> parameter settings</li></ol><h2 id="_2021-1-29-v1-4-2" tabindex="-1">2021.1.29 v1.4.2 <a class="header-anchor" href="#_2021-1-29-v1-4-2" aria-label="Permalink to &quot;2021.1.29 v1.4.2&quot;">​</a></h2><ol><li>Upgraded dependencies</li><li>Fixed bugs</li></ol><h2 id="_2021-1-11-v1-4-1" tabindex="-1">2021.1.11 v1.4.1 <a class="header-anchor" href="#_2021-1-11-v1-4-1" aria-label="Permalink to &quot;2021.1.11 v1.4.1&quot;">​</a></h2><ol><li>Upgraded get <code>config</code> method, upgraded update <code>config</code> method</li><li>Optimized reading <code>gitmars</code> config and git config</li><li>Changed config method, deprecating <code>gitmarsconfig.json</code>, using <code>.gitmarsrc</code></li><li>Fixed <code>Apollo</code> config issue</li></ol><h2 id="_2020-12-29-v1-4-0" tabindex="-1">2020.12.29 v1.4.0 <a class="header-anchor" href="#_2020-12-29-v1-4-0" aria-label="Permalink to &quot;2020.12.29 v1.4.0&quot;">​</a></h2><ol><li>Added <code>go</code> command, supports <code>admin.publish</code>/<code>build</code>/<code>combine</code>/<code>end</code>/<code>start</code>/<code>update</code></li></ol><h2 id="_2020-10-16-v1-3-6" tabindex="-1">2020.10.16 v1.3.6 <a class="header-anchor" href="#_2020-10-16-v1-3-6" aria-label="Permalink to &quot;2020.10.16 v1.3.6&quot;">​</a></h2><ol><li>Added <code>postmsg</code> command for pushing messages</li></ol><h2 id="_2020-08-14-v1-3-4" tabindex="-1">2020.08.14 v1.3.4 <a class="header-anchor" href="#_2020-08-14-v1-3-4" aria-label="Permalink to &quot;2020.08.14 v1.3.4&quot;">​</a></h2><ol><li><code>bugfix</code> branch with <code>--as-feature</code> no longer auto-merges to <code>bug</code> line</li><li>Extracted command config, preparing for <code>gitmars ui</code></li></ol><h2 id="_2020-08-14-v1-3-3" tabindex="-1">2020.08.14 v1.3.3 <a class="header-anchor" href="#_2020-08-14-v1-3-3" aria-label="Permalink to &quot;2020.08.14 v1.3.3&quot;">​</a></h2><ol><li>Changed method to get current branch status</li></ol><h2 id="_2020-08-02-v1-3-2" tabindex="-1">2020.08.02 v1.3.2 <a class="header-anchor" href="#_2020-08-02-v1-3-2" aria-label="Permalink to &quot;2020.08.02 v1.3.2&quot;">​</a></h2><ol><li>Changed method to get current branch name, fixed Windows compatibility</li></ol><h2 id="_2020-07-23-v1-3-1" tabindex="-1">2020.07.23 v1.3.1 <a class="header-anchor" href="#_2020-07-23-v1-3-1" aria-label="Permalink to &quot;2020.07.23 v1.3.1&quot;">​</a></h2><ol><li>Optimized <code>link</code>/<code>unlink</code> for Windows compatibility</li></ol><h2 id="_2020-07-22-v1-3-0" tabindex="-1">2020.07.22 v1.3.0 <a class="header-anchor" href="#_2020-07-22-v1-3-0" aria-label="Permalink to &quot;2020.07.22 v1.3.0&quot;">​</a></h2><ol><li>Added <code>link</code> command for creating local package symlinks</li></ol><h2 id="_2020-07-07-v1-2-9" tabindex="-1">2020.07.07 v1.2.9 <a class="header-anchor" href="#_2020-07-07-v1-2-9" aria-label="Permalink to &quot;2020.07.07 v1.2.9&quot;">​</a></h2><ol><li>Optimized <code>combine</code> command <code>status</code> check</li><li>Upgraded dependencies</li></ol><h2 id="_2020-07-07-v1-2-8" tabindex="-1">2020.07.07 v1.2.8 <a class="header-anchor" href="#_2020-07-07-v1-2-8" aria-label="Permalink to &quot;2020.07.07 v1.2.8&quot;">​</a></h2><ol><li>Fixed <code>jenkins</code> not starting bug</li></ol><h2 id="_2020-06-30-v1-2-7" tabindex="-1">2020.06.30 v1.2.7 <a class="header-anchor" href="#_2020-06-30-v1-2-7" aria-label="Permalink to &quot;2020.06.30 v1.2.7&quot;">​</a></h2><ol><li>Upgraded <code>combine</code>/<code>end</code>/<code>update</code> commands, branch name is optional, defaults to current branch</li><li><code>combine</code> command added <code>-a</code> and <code>-m</code> parameters for auto <code>add</code> and <code>commit</code></li><li>Upgraded documentation</li></ol><h2 id="_2020-06-27-v1-2-6" tabindex="-1">2020.06.27 v1.2.6 <a class="header-anchor" href="#_2020-06-27-v1-2-6" aria-label="Permalink to &quot;2020.06.27 v1.2.6&quot;">​</a></h2><ol><li>Upgraded <code>upgrade</code> command, Windows users can now use upgrade command!</li></ol><h2 id="_2020-06-27-v1-2-5" tabindex="-1">2020.06.27 v1.2.5 <a class="header-anchor" href="#_2020-06-27-v1-2-5" aria-label="Permalink to &quot;2020.06.27 v1.2.5&quot;">​</a></h2><ol><li>Upgraded <code>get</code>/<code>save</code> commands, stash now &quot;bound&quot; to git branch, added advanced usage</li><li>Fixed <code>config</code> command bug</li><li>Fixed <code>continue</code> command bug</li></ol><h2 id="_2020-06-16-v1-2-4" tabindex="-1">2020.06.16 v1.2.4 <a class="header-anchor" href="#_2020-06-16-v1-2-4" aria-label="Permalink to &quot;2020.06.16 v1.2.4&quot;">​</a></h2><ol><li>Fixed compatibility issue with node v14</li><li>Fixed missing package bug</li><li>Code transpiled to ES5 for publishing</li></ol><h2 id="_2020-05-29-v1-2-2" tabindex="-1">2020.05.29 v1.2.2 <a class="header-anchor" href="#_2020-05-29-v1-2-2" aria-label="Permalink to &quot;2020.05.29 v1.2.2&quot;">​</a></h2><ol><li>Added <code>build</code> command to trigger Jenkins build</li><li><code>combine</code> and <code>admin publish</code> commands added <code>--build</code> parameter to trigger Jenkins build after merging</li><li>Build config fetched from remote and cached for 24 hours, auto-refreshed after expiration or <code>gitm clean</code></li><li>Optimized code structure, cleaned redundant operations, improved performance</li><li>Fixed historical bugs</li></ol><h2 id="_2020-05-21-v1-1-2" tabindex="-1">2020.05.21 v1.1.2 <a class="header-anchor" href="#_2020-05-21-v1-1-2" aria-label="Permalink to &quot;2020.05.21 v1.1.2&quot;">​</a></h2><ol><li>Fixed <code>permission</code> occasional inaccurate detection (important)</li></ol><h2 id="_2020-05-19-v1-1-1" tabindex="-1">2020.05.19 v1.1.1 <a class="header-anchor" href="#_2020-05-19-v1-1-1" aria-label="Permalink to &quot;2020.05.19 v1.1.1&quot;">​</a></h2><ol><li>Added <code>clean</code> command to clear gitmars cache and config files</li><li><code>upgrade</code> command added <code>version</code> parameter for upgrading to specific version</li></ol><h2 id="_2020-05-19-v1-1-0" tabindex="-1">2020.05.19 v1.1.0 <a class="header-anchor" href="#_2020-05-19-v1-1-0" aria-label="Permalink to &quot;2020.05.19 v1.1.0&quot;">​</a></h2><ol><li>Added <code>permission</code> command to restrict direct commits to <code>master</code> branch</li><li>Optimized execution logic, allows running <code>gitm</code> in subdirectories</li><li>Optimized logging and execution output, no more large garbled text</li></ol><h2 id="_2020-05-15-v1-0-20" tabindex="-1">2020.05.15 v1.0.20 <a class="header-anchor" href="#_2020-05-15-v1-0-20" aria-label="Permalink to &quot;2020.05.15 v1.0.20&quot;">​</a></h2><ol><li>Fixed <code>copy</code> command bug</li></ol><h2 id="_2020-05-13-v1-0-19" tabindex="-1">2020.05.13 v1.0.19 <a class="header-anchor" href="#_2020-05-13-v1-0-19" aria-label="Permalink to &quot;2020.05.13 v1.0.19&quot;">​</a></h2><ol><li><code>update</code> command added <code>--use-merge</code> config</li><li><code>admin</code> command <code>--rebase</code> config changed to <code>--use-rebase</code></li></ol><h2 id="_2020-05-11-v1-0-18" tabindex="-1">2020.05.11 v1.0.18 <a class="header-anchor" href="#_2020-05-11-v1-0-18" aria-label="Permalink to &quot;2020.05.11 v1.0.18&quot;">​</a></h2><ol><li><code>copy</code> command removed keyword limit</li><li>Optimized version upgrade command</li><li>Optimized command execution prompts</li></ol><h2 id="_2020-04-28-v1-0-17" tabindex="-1">2020.04.28 v1.0.17 <a class="header-anchor" href="#_2020-04-28-v1-0-17" aria-label="Permalink to &quot;2020.04.28 v1.0.17&quot;">​</a></h2><ol><li><code>combine</code> command added <code>--as-feature</code> config, pass <code>--as-feature</code> when <code>bugfix</code> branch needs to merge to <code>release</code></li></ol><h2 id="_2020-04-17-v1-0-16" tabindex="-1">2020.04.17 v1.0.16 <a class="header-anchor" href="#_2020-04-17-v1-0-16" aria-label="Permalink to &quot;2020.04.17 v1.0.16&quot;">​</a></h2><ol><li>Optimized message prompts</li></ol><h2 id="_2020-04-08-v1-0-15" tabindex="-1">2020.04.08 v1.0.15 <a class="header-anchor" href="#_2020-04-08-v1-0-15" aria-label="Permalink to &quot;2020.04.08 v1.0.15&quot;">​</a></h2><ol><li>Optimized commands</li><li>Added <code>postmsg</code> support to commands</li></ol><h2 id="_2020-04-08-v1-0-14" tabindex="-1">2020.04.08 v1.0.14 <a class="header-anchor" href="#_2020-04-08-v1-0-14" aria-label="Permalink to &quot;2020.04.08 v1.0.14&quot;">​</a></h2><ol><li><code>combine</code> command allows <code>--no-bugfix</code> when merging <code>support</code> type branches to not merge to <code>bug</code> branch</li><li>Added <code>postmsg</code> switch</li><li>Optimized command execution message prompts</li></ol><h2 id="_2020-04-02-v1-0-13" tabindex="-1">2020.04.02 v1.0.13 <a class="header-anchor" href="#_2020-04-02-v1-0-13" aria-label="Permalink to &quot;2020.04.02 v1.0.13&quot;">​</a></h2><ol><li><code>gitm branch</code> supports setting remote branch association</li><li>Added <code>upgrade</code> method</li></ol><h2 id="_2020-03-31-v1-0-12" tabindex="-1">2020.03.31 v1.0.12 <a class="header-anchor" href="#_2020-03-31-v1-0-12" aria-label="Permalink to &quot;2020.03.31 v1.0.12&quot;">​</a></h2><ol><li><code>start</code> command now auto-pulls latest code when creating branch</li></ol><h2 id="_2020-03-27-v1-0-11" tabindex="-1">2020.03.27 v1.0.11 <a class="header-anchor" href="#_2020-03-27-v1-0-11" aria-label="Permalink to &quot;2020.03.27 v1.0.11&quot;">​</a></h2><ol><li>Updated <code>bugfix</code> and <code>release</code> branch support for forcing use of incoming or current code</li><li>Message push supports template config. Supported params: <code>message</code>, <code>time</code>, <code>project</code>, <code>pwd</code>(execution directory), <code>user</code>(local config username). Default template: <code>${message}; Project: ${project}; Path: ${pwd}</code></li></ol><h2 id="_2020-03-25-v1-0-10" tabindex="-1">2020.03.25 v1.0.10 <a class="header-anchor" href="#_2020-03-25-v1-0-10" aria-label="Permalink to &quot;2020.03.25 v1.0.10&quot;">​</a></h2><ol><li>Added message push</li><li>No longer blocks execution when switching branches with unversioned files</li><li>Optimized <code>admin</code> method</li></ol><h2 id="_2020-03-22-v1-0-9" tabindex="-1">2020.03.22 v1.0.9 <a class="header-anchor" href="#_2020-03-22-v1-0-9" aria-label="Permalink to &quot;2020.03.22 v1.0.9&quot;">​</a></h2><ol><li>Adjusted <code>admin</code> merge strategy</li><li>Fixed some Windows compatibility issues</li></ol><h2 id="_2020-03-18-v1-0-8" tabindex="-1">2020.03.18 v1.0.8 <a class="header-anchor" href="#_2020-03-18-v1-0-8" aria-label="Permalink to &quot;2020.03.18 v1.0.8&quot;">​</a></h2><ol><li>Added <code>support</code> branch support</li></ol><h2 id="_2020-03-08-v1-0-7" tabindex="-1">2020.03.08 v1.0.7 <a class="header-anchor" href="#_2020-03-08-v1-0-7" aria-label="Permalink to &quot;2020.03.08 v1.0.7&quot;">​</a></h2><ol><li>Optimized <code>gitm revert</code> functionality</li><li>Optimized command execution prompt method</li></ol><h2 id="_2020-03-04-v1-0-6" tabindex="-1">2020.03.04 v1.0.6 <a class="header-anchor" href="#_2020-03-04-v1-0-6" aria-label="Permalink to &quot;2020.03.04 v1.0.6&quot;">​</a></h2><ol><li><code>admin</code> added <code>clean</code> command for Jenkins build branch cleanup</li><li>Updated <code>readme</code></li></ol><h2 id="_2020-03-02-v1-0-5" tabindex="-1">2020.03.02 v1.0.5 <a class="header-anchor" href="#_2020-03-02-v1-0-5" aria-label="Permalink to &quot;2020.03.02 v1.0.5&quot;">​</a></h2><ol><li>Added <code>continue</code> and <code>branch</code> methods</li><li>Improved execution main program</li><li>Added <code>log</code></li><li>Improved <code>copy</code> functionality</li><li>Fixed some bugs</li><li>Optimized command execution methods</li><li>Optimized code</li><li>Improved <code>readme</code></li><li>Improved <code>end</code> and <code>start</code> functionality</li><li>Improved <code>admin</code> functionality: <code>update</code>, <code>create</code>, <code>publish</code></li></ol>',333)]))}const v=o(l,[["render",c]]);export{u as __pageData,v as default};
